		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state parameter to prevent CSRF attacks
	state, err := generateRandomState()
	if err != nil {
		return "", err
	}

	// Validate redirectPath to prevent open redirect vulnerabilities
	if err := validateRedirectURL(redirectPath); err != nil {
		return "", err
	}

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	if redirectPath != "" {
		config.RedirectURL = redirectPath
	}

	// Generate the authorization URL with the state parameter
	authURL := config.AuthCodeURL(state)

	// Set the state in a secure, HTTP-only cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		Path:     "/",
		MaxAge:   600, // 10 minutes expiration to limit attack window
	})

	return authURL, nil
}

// generateRandomState generates a cryptographically secure random state string
func generateRandomState() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// validateRedirectURL validates that the redirect URL is safe and prevents open redirects
func validateRedirectURL(redirectPath string) error {
	if redirectPath == "" {
		return nil
	}

	u, err := url.Parse(redirectPath)
	if err != nil {
		return err
	}

	// If it's an absolute URL, validate it matches the configured redirect domain
	if u.IsAbs() {
		baseURL, err := url.Parse(OAuthConfig.RedirectURL)
		if err != nil {
			return err
		}

		// Strict validation: scheme, host, and port must match to prevent open redirects
		if u.Scheme != baseURL.Scheme || u.Host != baseURL.Host {
			return errors.New("invalid redirect URL: must match application domain")
		}
	} else {
		// For relative URLs, ensure they start with / to prevent protocol-relative URLs (//attacker.com)
		if !strings.HasPrefix(redirectPath, "/") {
			return errors.New("invalid redirect path: must be absolute path starting with /")
		}
	}

	return nil
}

