	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
// If redirectPath is a relative path (e.g., "/callback"), it will be resolved against the current request.
// If redirectPath is an absolute URL, it will be used as-is.
// The session parameter is available for session validation if needed by the caller.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state to prevent CSRF attacks
	state, err := generateRandomState()
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config to avoid modifying the global configuration
	config := *OAuthConfig

	// Determine the redirect URL based on redirectPath
	if redirectPath != "" {
		if u, parseErr := url.Parse(redirectPath); parseErr == nil && u.IsAbs() {
			// redirectPath is an absolute URL, use it directly
			config.RedirectURL = redirectPath
		} else {
			// redirectPath is a relative path, construct full URL from request
			scheme := "http"
			if r.TLS != nil {
				scheme = "https"
			}
			// Check for proxy headers in case the app is behind a load balancer
			if forwardedProto := r.Header.Get("X-Forwarded-Proto"); forwardedProto != "" {
				scheme = forwardedProto
			}
			config.RedirectURL = scheme + "://" + r.Host + redirectPath
		}
	}

	// Generate the authorization URL with the state parameter
	authURL := config.AuthCodeURL(state)

	// Determine if the request is secure for cookie flags
	isSecure := r.TLS != nil || r.Header.Get("X-Forwarded-Proto") == "https"

	// Set the state in a cookie for later validation during the callback
	// This implements the "double submit cookie" pattern for CSRF protection
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   isSecure,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   600, // 10 minutes
	})

	return authURL, nil
}

