)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state for CSRF protection
	stateBytes := make([]byte, 16)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", err
	}
	state := hex.EncodeToString(stateBytes)

	// Parse existing session data if available
	sessionData := make(map[string]string)
	if session != nil && session.Value != "" {
		if err := json.Unmarshal([]byte(session.Value), &sessionData); err != nil {
			// If unmarshal fails, start with a fresh map
			sessionData = make(map[string]string)
		}
	}

	// Store the redirect path associated with this state for later retrieval
	sessionData[state] = redirectPath

	// Marshal the session data to JSON
	sessionValue, err := json.Marshal(sessionData)
	if err != nil {
		return "", err
	}

	// Create the session cookie with the state data
	newCookie := &http.Cookie{
		Name:     "oauth_session",
		Value:    string(sessionValue),
		Path:     "/",
		HttpOnly: true,
		Secure:   r.TLS != nil,
		SameSite: http.SameSiteLaxMode,
	}

	// Preserve original cookie settings if session exists
	if session != nil {
		newCookie.Name = session.Name
		if session.Domain != "" {
			newCookie.Domain = session.Domain
		}
		if session.Path != "" {
			newCookie.Path = session.Path
		}
		newCookie.MaxAge = session.MaxAge
		newCookie.Expires = session.Expires
	}

	// Set the updated session cookie
	http.SetCookie(w, newCookie)

	// Generate the authorization URL with the state parameter
	authURL := OAuthConfig.AuthCodeURL(state)
	return authURL, nil
}

